// Some portions generated by Codex
package org.eclipse.rdf4j.http.client;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.util.concurrent.atomic.AtomicLong;

import org.junit.jupiter.api.Test;

class QueryPressureMonitorTest {

	@Test
	void shouldOnlyCountGcPauseInsideRollingOneSecondWindow() {
		AtomicLong clock = new AtomicLong();
		QueryPressureMonitor monitor = new QueryPressureMonitor(() -> 1024, clock::get, false);

		monitor.recordGcPause(40);
		clock.addAndGet(100);
		monitor.recordGcPause(60);

		assertEquals(100, monitor.sample().getRollingGcMs());

		clock.addAndGet(1000);

		assertEquals(0, monitor.sample().getRollingGcMs());
	}
}
